fun solve(nums: Array<Long>, k: Long): Long {
    val sorted = nums.sorted()
    val n = sorted.size
    var maxLen = 1L
    for (i in 0 until n) {
        val target = sorted[i] * k
        var low = i
        var high = n - 1
        var best = i
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted[mid] <= target) {
                best = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        val currentLen = best - i + 1
        maxLen = max(maxLen, currentLen.toLong())
    }
    return n.toLong() - maxLen
}
